mapper.select:
SELECT id, user_id, name, os_type, status, last_seen, created_at, agent_id,
       agent_secret_hash, agent_secret_issued_at, update_status,
       update_current_sha, update_latest_sha, update_message, update_checked_at
FROM nodes
WHERE id = #{nodeId}
  AND user_id = #{userId}

mapper.update:
UPDATE nodes
SET status = #{status}
WHERE id = #{id}
  AND status <> 'D'

UPDATE nodes
SET status = 'D'
WHERE id = #{id}
